class TaskManager:
    def __init__(self):
        self.tasks = []
    def add_task(self, name, priority=False):
        if priority:
            self.tasks.insert(0, name)
        else:
            self.tasks.append(name)
    def remove_task(self, name):
        if name in self.tasks:
            self.tasks.remove(name)
    def get_tasks(self):
        return self.tasks
